import { spawn } from "child_process";
import path from "path";
import { readFile } from "fs/promises";

const PYTHON_SCRIPT = path.join(
  import.meta.dirname,
  "..",
  "..",
  "..",
  "pdf-to-markdown",
  "convert-docling.py"
);

export async function convertPdfToMarkdown(
  pdfPath: string,
  outputPath: string
): Promise<string> {
  return new Promise((resolve, reject) => {
    const proc = spawn("python3", [
      PYTHON_SCRIPT,
      "--input",
      pdfPath,
      "--output",
      outputPath,
    ]);

    let stderr = "";

    proc.stderr.on("data", (data: Buffer) => {
      stderr += data.toString();
    });

    proc.on("close", async (code: number | null) => {
      if (code !== 0) {
        reject(new Error(`PDF conversion failed: ${stderr}`));
        return;
      }

      try {
        const markdown = await readFile(outputPath, "utf-8");
        resolve(markdown);
      } catch (err) {
        reject(err);
      }
    });

    proc.on("error", (err: Error) => {
      reject(new Error(`Failed to spawn converter: ${err.message}`));
    });
  });
}

import { ChatOpenAI } from "@langchain/openai";
import { ChatPromptTemplate } from "@langchain/core/prompts";

function getModel(): ChatOpenAI {
  const endpoint = process.env.OPENAI_ENDPOINT || "https://api.openai.com/v1/chat/completions";
  const baseURL = endpoint.replace(/\/chat\/completions\/?$/, "");

  return new ChatOpenAI({
    model: process.env.OPENAI_MODEL || "gpt-4o",
    apiKey: process.env.OPENAI_KEY,
    temperature: 0.7,
    configuration: {
      baseURL,
    },
  });
}

const PLAN_PROMPT = ChatPromptTemplate.fromTemplate(`
You are an expert educator designing a structured lesson from educational content.
Analyze the following document and create a detailed learning plan.

DOCUMENT CONTENT:
{document}

Generate a JSON response with this exact structure:
{{
  "title": "A descriptive title for this lesson",
  "description": "A brief 1-2 sentence overview of what the learner will gain",
  "difficulty": "beginner" | "intermediate" | "advanced",
  "objectives": [
    {{
      "text": "A clear, specific, measurable learning objective",
      "key_concepts": ["concept1", "concept2"]
    }}
  ]
}}

Rules:
- Generate 4-7 learning objectives
- Each objective must be directly derived from the document content
- Objectives should progress from foundational to advanced
- Assess difficulty based on the complexity of the material
- key_concepts should be 2-4 terms/key ideas for each objective

Respond ONLY with valid JSON. No markdown, no explanation.`);

const MCQ_PROMPT = ChatPromptTemplate.fromTemplate(`
You are an expert quiz creator. Create multiple-choice questions to test understanding of a specific learning objective.

DOCUMENT CONTEXT:
{document}

LEARNING OBJECTIVE: {objective}

KEY CONCEPTS: {concepts}

Generate a JSON array of exactly {count} MCQ questions:
[
  {{
    "question": "The question text",
    "choices": ["Choice A", "Choice B", "Choice C", "Choice D"],
    "correctIndex": 0,
    "explanation": "Brief explanation of why this is correct"
  }}
]

Rules:
- Questions must test understanding, not just memorization
- All choices should be plausible (good distractors)
- Each question must relate directly to the learning objective
- Provide exactly 4 choices per question
- correctIndex is 0-based
- Explanations should be 1-2 sentences

Respond ONLY with valid JSON array. No markdown, no explanation.`);

const HINT_PROMPT = ChatPromptTemplate.fromTemplate(`
You are a supportive tutor helping a student who answered incorrectly. Provide a helpful hint WITHOUT giving away the answer.

DOCUMENT CONTEXT:
{document}

QUESTION: {question}

CHOICES: {choices}

STUDENT'S INCORRECT ANSWER: {userAnswer}

YOUR TASK: Provide a gentle hint that guides the student toward the correct answer. Do NOT state the correct answer directly. Focus on the concept they need to reconsider. Keep it to 1-2 sentences.`);

const LEARN_MORE_PROMPT = ChatPromptTemplate.fromTemplate(`
You are a knowledgeable tutor explaining a concept in more depth.

DOCUMENT CONTEXT:
{document}

TOPIC: {topic}
LEARNING OBJECTIVE: {objective}

Provide a clear, concise explanation of this topic (3-4 sentences). Break it down in an accessible way. Do NOT ask questions or quiz the student.`);

const SUMMARY_PROMPT = ChatPromptTemplate.fromTemplate(`
You are an encouraging educator providing a final progress report and study recommendations.

LESSON TITLE: {title}
DIFFICULTY: {difficulty}

OBJECTIVES AND RESULTS:
{objectivesResults}

OVERALL SCORE: {score}%

Generate a JSON response:
{{
  "overall_feedback": "2-3 sentences summarizing performance with encouragement",
  "strengths": ["area of strength 1", "area of strength 2"],
  "areas_for_improvement": ["area 1", "area 2"],
  "study_tips": ["tip 1", "tip 2", "tip 3"]
}}

Respond ONLY with valid JSON. No markdown, no explanation.`);

export interface LearningObjective {
  text: string;
  key_concepts: string[];
}

export interface LessonPlan {
  title: string;
  description: string;
  difficulty: string;
  objectives: LearningObjective[];
}

export interface MCQ {
  question: string;
  choices: string[];
  correctIndex: number;
  explanation: string;
}

export interface Summary {
  overall_feedback: string;
  strengths: string[];
  areas_for_improvement: string[];
  study_tips: string[];
}

export async function generateLessonPlan(markdown: string): Promise<LessonPlan> {
  const model = getModel();
  const chain = PLAN_PROMPT.pipe(model);
  const result = await chain.invoke({ document: markdown.slice(0, 32000) });
  const text = String(result.content).trim();
  const cleaned = text.replace(/^```(?:json)?\s*/, "").replace(/\s*```$/, "");
  return JSON.parse(cleaned);
}

export async function generateMCQs(
  markdown: string,
  objective: string,
  concepts: string[],
  count: number = 3
): Promise<MCQ[]> {
  const model = getModel();
  const chain = MCQ_PROMPT.pipe(model);
  const result = await chain.invoke({
    document: markdown.slice(0, 24000),
    objective,
    concepts: concepts.join(", "),
    count: String(count),
  });
  const text = String(result.content).trim();
  const cleaned = text.replace(/^```(?:json)?\s*/, "").replace(/\s*```$/, "");
  return JSON.parse(cleaned);
}

export async function generateHint(
  markdown: string,
  question: string,
  choices: string[],
  userAnswer: string
): Promise<string> {
  const model = getModel();
  const chain = HINT_PROMPT.pipe(model);
  const result = await chain.invoke({
    document: markdown.slice(0, 16000),
    question,
    choices: choices.join(", "),
    userAnswer,
  });
  return String(result.content).trim();
}

export async function learnMore(
  markdown: string,
  topic: string,
  objective: string
): Promise<string> {
  const model = getModel();
  const chain = LEARN_MORE_PROMPT.pipe(model);
  const result = await chain.invoke({
    document: markdown.slice(0, 24000),
    topic,
    objective,
  });
  return String(result.content).trim();
}

export async function generateSummary(
  title: string,
  difficulty: string,
  objectivesResults: Array<{ text: string; correct: number; total: number }>,
  score: number
): Promise<Summary> {
  const model = getModel();
  const chain = SUMMARY_PROMPT.pipe(model);
  const result = await chain.invoke({
    title,
    difficulty,
    objectivesResults: objectivesResults
      .map((o) => `- ${o.text}: ${o.correct}/${o.total} correct`)
      .join("\n"),
    score: String(Math.round(score)),
  });
  const text = String(result.content).trim();
  const cleaned = text.replace(/^```(?:json)?\s*/, "").replace(/\s*```$/, "");
  return JSON.parse(cleaned);
}

import { FastifyInstance } from "fastify";
import { getDb } from "../db.js";
import { writeFile, mkdir, unlink } from "fs/promises";
import { createWriteStream } from "fs";
import path from "path";
import { pipeline } from "stream/promises";
import { convertPdfToMarkdown } from "../services/converter.js";

const UPLOADS_DIR = path.join(import.meta.dirname, "..", "..", "uploads");

export async function pdfRoutes(fastify: FastifyInstance) {
  await mkdir(UPLOADS_DIR, { recursive: true });

  fastify.get("/api/pdf", async (_request, reply) => {
    const db = getDb();
    const pdfs = db
      .prepare(
        `SELECT p.id, p.filename, p.created_at, 
          CASE WHEN lp.status IS NULL THEN 'uploaded' ELSE lp.status END as status
         FROM pdfs p
         LEFT JOIN lesson_plans lp ON lp.pdf_id = p.id
         ORDER BY p.created_at DESC`
      )
      .all();
    return reply.send(pdfs);
  });

  fastify.post("/api/pdf/upload", async (request, reply) => {
    const data = await request.file();

    if (!data) {
      return reply.status(400).send({ error: "No file uploaded" });
    }

    if (!data.mimetype.includes("pdf")) {
      return reply.status(400).send({ error: "Only PDF files are accepted" });
    }

    const filename = data.filename;
    const filepath = path.join(UPLOADS_DIR, `${Date.now()}-${filename}`);

    await pipeline(data.file, createWriteStream(filepath));

    const markdownPath = filepath.replace(/\.pdf$/i, ".md");
    let markdownContent = "";

    try {
      markdownContent = await convertPdfToMarkdown(filepath, markdownPath);
    } catch (err) {
      fastify.log.error("PDF conversion error:", err);
    }

    const db = getDb();
    const stmt = db.prepare(
      `INSERT INTO pdfs (filename, filepath, markdown_path, markdown_content) VALUES (?, ?, ?, ?)`
    );
    const result = stmt.run(filename, filepath, markdownPath, markdownContent);

    return reply.send({
      id: result.lastInsertRowid,
      filename,
      markdownContent: markdownContent.slice(0, 500) + "...",
    });
  });

  fastify.get("/api/pdf/:id", async (request, reply) => {
    const { id } = request.params as { id: string };
    const db = getDb();
    const pdf = db.prepare("SELECT * FROM pdfs WHERE id = ?").get(Number(id));

    if (!pdf) {
      return reply.status(404).send({ error: "PDF not found" });
    }

    return reply.send(pdf);
  });

  fastify.delete("/api/pdf/:id", async (request, reply) => {
    const { id } = request.params as { id: string };
    const db = getDb();
    const pdf = db
      .prepare("SELECT * FROM pdfs WHERE id = ?")
      .get(Number(id)) as any;

    if (!pdf) {
      return reply.status(404).send({ error: "PDF not found" });
    }

    try {
      await unlink(pdf.filepath);
    } catch {}
    if (pdf.markdown_path) {
      try {
        await unlink(pdf.markdown_path);
      } catch {}
    }

    db.prepare("DELETE FROM pdfs WHERE id = ?").run(Number(id));
    return reply.send({ success: true });
  });
}

import { FastifyInstance } from "fastify";
import { getDb } from "../db.js";
import { generateLessonPlan, generateSummary } from "../services/agent.js";

export async function lessonRoutes(fastify: FastifyInstance) {
  fastify.post("/api/lesson/:pdfId/generate-plan", async (request, reply) => {
    const { pdfId } = request.params as { pdfId: string };
    const db = getDb();

    const pdf = db
      .prepare("SELECT * FROM pdfs WHERE id = ?")
      .get(Number(pdfId)) as any;

    if (!pdf) {
      return reply.status(404).send({ error: "PDF not found" });
    }

    if (!pdf.markdown_content) {
      return reply
        .status(400)
        .send({ error: "PDF has not been processed yet" });
    }

    const plan = await generateLessonPlan(pdf.markdown_content);

    const stmt = db.prepare(
      `INSERT INTO lesson_plans (pdf_id, objectives, difficulty, status) VALUES (?, ?, ?, 'draft')`
    );

    const result = stmt.run(
      Number(pdfId),
      JSON.stringify(plan.objectives.map((o) => ({ ...o, completed: false }))),
      plan.difficulty
    );

    return reply.send({
      id: Number(result.lastInsertRowid),
      pdfId: Number(pdfId),
      title: plan.title,
      description: plan.description,
      difficulty: plan.difficulty,
      objectives: plan.objectives.map((o) => ({ ...o, completed: false })),
      status: "draft",
    });
  });

  fastify.get("/api/lesson/:pdfId", async (request, reply) => {
    const { pdfId } = request.params as { pdfId: string };
    const db = getDb();

    const lessonPlan = db
      .prepare("SELECT * FROM lesson_plans WHERE pdf_id = ? ORDER BY id DESC LIMIT 1")
      .get(Number(pdfId)) as any;

    if (!lessonPlan) {
      return reply
        .status(404)
        .send({ error: "No lesson plan found for this PDF" });
    }

    return reply.send({
      id: lessonPlan.id,
      pdfId: lessonPlan.pdf_id,
      difficulty: lessonPlan.difficulty,
      objectives: JSON.parse(lessonPlan.objectives),
      status: lessonPlan.status,
      createdAt: lessonPlan.created_at,
    });
  });

  fastify.put("/api/lesson/:id/approve", async (request, reply) => {
    const { id } = request.params as { id: string };
    const db = getDb();

    db.prepare("UPDATE lesson_plans SET status = 'approved' WHERE id = ?").run(
      Number(id)
    );

    return reply.send({ success: true });
  });

  fastify.put("/api/lesson/:id/objectives", async (request, reply) => {
    const { id } = request.params as { id: string };
    const { objectives, difficulty } = request.body as any;
    const db = getDb();

    db.prepare(
      "UPDATE lesson_plans SET objectives = ?, difficulty = ?, status = 'approved' WHERE id = ?"
    ).run(JSON.stringify(objectives), difficulty || "intermediate", Number(id));

    return reply.send({ success: true });
  });

  fastify.get("/api/lesson/:id/summary", async (request, reply) => {
    const { id } = request.params as { id: string };
    const db = getDb();

    const lessonPlan = db
      .prepare("SELECT * FROM lesson_plans WHERE id = ?")
      .get(Number(id)) as any;

    if (!lessonPlan) {
      return reply.status(404).send({ error: "Lesson plan not found" });
    }

    const results = db
      .prepare("SELECT * FROM quiz_results WHERE lesson_plan_id = ?")
      .all(Number(id)) as any[];

    const objectivesResults = results.map((r: any) => ({
      objectiveIndex: r.objective_index,
      text: r.objective_text,
      correct: r.correct_answers,
      total: r.total_questions,
    }));

    const totalCorrect = results.reduce(
      (sum: number, r: any) => sum + r.correct_answers,
      0
    );
    const totalQuestions = results.reduce(
      (sum: number, r: any) => sum + r.total_questions,
      0
    );
    const score = totalQuestions > 0 ? (totalCorrect / totalQuestions) * 100 : 0;

    const pdf = db
      .prepare("SELECT * FROM pdfs WHERE id = ?")
      .get(lessonPlan.pdf_id) as any;

    const allObjectives = JSON.parse(lessonPlan.objectives);
    for (const obj of allObjectives) {
      if (!objectivesResults.find((r: any) => r.text === obj.text)) {
        objectivesResults.push({
          objectiveIndex: allObjectives.indexOf(obj),
          text: obj.text,
          correct: 0,
          total: 0,
        });
      }
    }

    const summary = await generateSummary(
      "Lesson",
      lessonPlan.difficulty,
      objectivesResults,
      score
    );

    db.prepare("UPDATE lesson_plans SET status = 'completed' WHERE id = ?").run(
      Number(id)
    );

    return reply.send({
      score: Math.round(score),
      totalCorrect,
      totalQuestions,
      objectivesResults,
      overallFeedback: summary.overall_feedback,
      strengths: summary.strengths,
      areasForImprovement: summary.areas_for_improvement,
      studyTips: summary.study_tips,
    });
  });
}

import { FastifyInstance } from "fastify";
import { getDb } from "../db.js";
import { generateMCQs, generateHint, learnMore } from "../services/agent.js";

export async function quizRoutes(fastify: FastifyInstance) {
  fastify.post("/api/quiz/generate", async (request, reply) => {
    const { lessonPlanId, objectiveIndex } = request.body as {
      lessonPlanId: number;
      objectiveIndex: number;
    };
    const db = getDb();

    const lessonPlan = db
      .prepare("SELECT * FROM lesson_plans WHERE id = ?")
      .get(lessonPlanId) as any;

    if (!lessonPlan) {
      return reply.status(404).send({ error: "Lesson plan not found" });
    }

    const objectives = JSON.parse(lessonPlan.objectives);
    const objective = objectives[objectiveIndex];

    if (!objective) {
      return reply.status(400).send({ error: "Invalid objective index" });
    }

    const pdf = db
      .prepare("SELECT * FROM pdfs WHERE id = ?")
      .get(lessonPlan.pdf_id) as any;

    const mcqs = await generateMCQs(
      pdf.markdown_content,
      objective.text,
      objective.key_concepts || [],
      3
    );

    return reply.send({
      lessonPlanId,
      objectiveIndex,
      objectiveText: objective.text,
      questions: mcqs,
    });
  });

  fastify.post("/api/quiz/submit-result", async (request, reply) => {
    const { lessonPlanId, objectiveIndex, objectiveText, totalQuestions, correctAnswers } =
      request.body as {
        lessonPlanId: number;
        objectiveIndex: number;
        objectiveText: string;
        totalQuestions: number;
        correctAnswers: number;
      };
    const db = getDb();

    const existing = db
      .prepare(
        "SELECT * FROM quiz_results WHERE lesson_plan_id = ? AND objective_index = ?"
      )
      .get(lessonPlanId, objectiveIndex) as any;

    if (existing) {
      db.prepare(
        "UPDATE quiz_results SET total_questions = ?, correct_answers = ? WHERE id = ?"
      ).run(totalQuestions, correctAnswers, existing.id);
    } else {
      db.prepare(
        "INSERT INTO quiz_results (lesson_plan_id, objective_index, objective_text, total_questions, correct_answers) VALUES (?, ?, ?, ?, ?)"
      ).run(lessonPlanId, objectiveIndex, objectiveText, totalQuestions, correctAnswers);
    }

    const objectives = JSON.parse(
      (
        db
          .prepare("SELECT objectives FROM lesson_plans WHERE id = ?")
          .get(lessonPlanId) as any
      ).objectives
    );

    objectives[objectiveIndex].completed = correctAnswers >= totalQuestions;

    db.prepare(
      "UPDATE lesson_plans SET objectives = ? WHERE id = ?"
    ).run(JSON.stringify(objectives), lessonPlanId);

    return reply.send({ success: true });
  });

  fastify.post("/api/quiz/hint", async (request, reply) => {
    const { lessonPlanId, question, choices, userAnswer } = request.body as {
      lessonPlanId: number;
      question: string;
      choices: string[];
      userAnswer: string;
    };
    const db = getDb();

    const lessonPlan = db
      .prepare("SELECT * FROM lesson_plans WHERE id = ?")
      .get(lessonPlanId) as any;

    const pdf = db
      .prepare("SELECT * FROM pdfs WHERE id = ?")
      .get(lessonPlan.pdf_id) as any;

    const hint = await generateHint(
      pdf.markdown_content,
      question,
      choices,
      userAnswer
    );

    return reply.send({ hint });
  });

  fastify.post("/api/quiz/learn-more", async (request, reply) => {
    const { lessonPlanId, topic, objective } = request.body as {
      lessonPlanId: number;
      topic: string;
      objective: string;
    };
    const db = getDb();

    const lessonPlan = db
      .prepare("SELECT * FROM lesson_plans WHERE id = ?")
      .get(lessonPlanId) as any;

    const pdf = db
      .prepare("SELECT * FROM pdfs WHERE id = ?")
      .get(lessonPlan.pdf_id) as any;

    const explanation = await learnMore(
      pdf.markdown_content,
      topic,
      objective
    );

    return reply.send({ explanation });
  });

  fastify.get("/api/quiz/progress/:lessonPlanId", async (request, reply) => {
    const { lessonPlanId } = request.params as { lessonPlanId: string };
    const db = getDb();

    const lessonPlan = db
      .prepare("SELECT * FROM lesson_plans WHERE id = ?")
      .get(Number(lessonPlanId)) as any;

    if (!lessonPlan) {
      return reply.status(404).send({ error: "Lesson plan not found" });
    }

    const objectives = JSON.parse(lessonPlan.objectives);
    const results = db
      .prepare("SELECT * FROM quiz_results WHERE lesson_plan_id = ?")
      .all(Number(lessonPlanId)) as any[];

    return reply.send({
      lessonPlanId: Number(lessonPlanId),
      status: lessonPlan.status,
      objectives: objectives.map((o: any, i: number) => {
        const result = results.find((r: any) => r.objective_index === i);
        return {
          index: i,
          text: o.text,
          completed: o.completed,
          correct: result?.correct_answers || 0,
          total: result?.total_questions || 0,
        };
      }),
    });
  });
}

