export interface PdfDocument {
  id: number;
  filename: string;
  created_at: string;
  status: "uploaded" | "draft" | "approved" | "completed";
}

export interface LearningObjective {
  text: string;
  key_concepts: string[];
  completed: boolean;
}

export interface LessonPlan {
  id: number;
  pdfId: number;
  title?: string;
  description?: string;
  difficulty: "beginner" | "intermediate" | "advanced";
  objectives: LearningObjective[];
  status: "draft" | "approved" | "completed";
}

export interface MCQ {
  question: string;
  choices: string[];
  correctIndex: number;
  explanation: string;
}

export interface QuizSession {
  lessonPlanId: number;
  objectiveIndex: number;
  objectiveText: string;
  questions: MCQ[];
  currentQuestionIndex: number;
  answers: (number | null)[];
  feedback: {
    type: "correct" | "incorrect" | null;
    message: string;
    questionIndex: number;
  };
}

export interface ObjectiveResult {
  objectiveIndex: number;
  text: string;
  correct: number;
  total: number;
}

export interface LessonSummary {
  score: number;
  totalCorrect: number;
  totalQuestions: number;
  objectivesResults: ObjectiveResult[];
  overallFeedback: string;
  strengths: string[];
  areasForImprovement: string[];
  studyTips: string[];
}

export type AppScreen = "home" | "lesson-plan" | "quiz" | "summary";

const API_BASE = "http://localhost:3003/api";

async function request<T>(url: string, options?: RequestInit): Promise<T> {
  const res = await fetch(`${API_BASE}${url}`, {
    headers: { "Content-Type": "application/json" },
    ...options,
  });
  if (!res.ok) {
    const err = await res.json().catch(() => ({ error: "Request failed" }));
    throw new Error(err.error || `HTTP ${res.status}`);
  }
  return res.json();
}

export const api = {
  getPdfs: () => request<any[]>(`/pdf`),

  uploadPdf: (file: File) => {
    const formData = new FormData();
    formData.append("file", file);
    return fetch(`${API_BASE}/pdf/upload`, {
      method: "POST",
      body: formData,
    }).then((r) => {
      if (!r.ok) throw new Error("Upload failed");
      return r.json();
    });
  },

  deletePdf: (id: number) =>
    request(`/pdf/${id}`, { method: "DELETE" }),

  getPdf: (id: number) => request<any>(`/pdf/${id}`),

  generateLessonPlan: (pdfId: number) =>
    request<any>(`/lesson/${pdfId}/generate-plan`, { method: "POST" }),

  getLessonPlan: (pdfId: number) =>
    request<any>(`/lesson/${pdfId}`),

  approveLessonPlan: (id: number) =>
    request(`/lesson/${id}/approve`, { method: "PUT" }),

  updateObjectives: (id: number, objectives: any[], difficulty: string) =>
    request(`/lesson/${id}/objectives`, {
      method: "PUT",
      body: JSON.stringify({ objectives, difficulty }),
    }),

  generateQuiz: (lessonPlanId: number, objectiveIndex: number) =>
    request<any>(`/quiz/generate`, {
      method: "POST",
      body: JSON.stringify({ lessonPlanId, objectiveIndex }),
    }),

  submitResult: (data: {
    lessonPlanId: number;
    objectiveIndex: number;
    objectiveText: string;
    totalQuestions: number;
    correctAnswers: number;
  }) =>
    request(`/quiz/submit-result`, {
      method: "POST",
      body: JSON.stringify(data),
    }),

  getHint: (data: {
    lessonPlanId: number;
    question: string;
    choices: string[];
    userAnswer: string;
  }) =>
    request<{ hint: string }>(`/quiz/hint`, {
      method: "POST",
      body: JSON.stringify(data),
    }),

  learnMore: (data: {
    lessonPlanId: number;
    topic: string;
    objective: string;
  }) =>
    request<{ explanation: string }>(`/quiz/learn-more`, {
      method: "POST",
      body: JSON.stringify(data),
    }),

  getProgress: (lessonPlanId: number) =>
    request<any>(`/quiz/progress/${lessonPlanId}`),

  getSummary: (lessonPlanId: number) =>
    request<any>(`/lesson/${lessonPlanId}/summary`),
};

