import { useCallback, useState, type DragEvent } from "react";
import { Upload, FileText, Loader2 } from "lucide-react";
import { Button } from "#components/ui/button";
import { cn } from "#lib/utils";

interface FileUploadProps {
  onUpload: (file: File) => Promise<void>;
  loading?: boolean;
}

export function FileUpload({ onUpload, loading }: FileUploadProps) {
  const [dragOver, setDragOver] = useState(false);

  const handleDrop = useCallback(
    (e: DragEvent) => {
      e.preventDefault();
      setDragOver(false);
      const file = e.dataTransfer.files[0];
      if (file && file.type === "application/pdf") {
        onUpload(file);
      }
    },
    [onUpload]
  );

  const handleChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) onUpload(file);
    },
    [onUpload]
  );

  return (
    <div
      className={cn(
        "relative flex flex-col items-center justify-center rounded-2xl border-2 border-dashed p-12 transition-all duration-200",
        dragOver
          ? "border-primary bg-primary/5 scale-[1.02]"
          : "border-border bg-card hover:border-primary/50 hover:bg-muted/50",
        loading && "pointer-events-none opacity-60"
      )}
      onDragOver={(e) => {
        e.preventDefault();
        setDragOver(true);
      }}
      onDragLeave={() => setDragOver(false)}
      onDrop={handleDrop}
    >
      <input
        type="file"
        accept="application/pdf"
        onChange={handleChange}
        className="absolute inset-0 cursor-pointer opacity-0"
        disabled={loading}
      />

      {loading ? (
        <div className="flex flex-col items-center gap-3">
          <Loader2 className="size-12 animate-spin text-primary" />
          <p className="text-sm font-medium text-muted-foreground">
            Processing PDF...
          </p>
        </div>
      ) : (
        <>
          <div className="mb-4 flex size-16 items-center justify-center rounded-2xl bg-gradient-to-br from-blue-500 to-indigo-600 shadow-lg shadow-indigo-500/25">
            <Upload className="size-7 text-white" />
          </div>
          <h3 className="mb-1 text-lg font-semibold">Upload your PDF</h3>
          <p className="mb-4 text-sm text-muted-foreground">
            Drag & drop your PDF here, or click to browse
          </p>
          <div className="flex items-center gap-2 text-xs text-muted-foreground">
            <FileText className="size-3.5" />
            <span>Supports PDF files up to 100MB</span>
          </div>
        </>
      )}
    </div>
  );
}

