import { useState } from "react";
import {
  GraduationCap,
  Plus,
  Trash2,
  Play,
  Edit3,
  Check,
  X,
  ArrowLeft,
  Loader2,
  Target,
} from "lucide-react";
import { Button } from "#components/ui/button";
import { Badge } from "#components/ui/badge";
import { Progress } from "#components/ui/progress";
import { Card, CardContent, CardHeader, CardTitle } from "#components/ui/card";
import { Skeleton } from "#components/ui/skeleton";
import type { LearningObjective } from "../types";

interface LessonPlanProps {
  title?: string;
  description?: string;
  difficulty: string;
  objectives: LearningObjective[];
  loading: boolean;
  onApprove: () => void;
  onUpdateObjectives: (objectives: LearningObjective[], difficulty: string) => void;
  onBack: () => void;
}

const difficultyConfig: Record<
  string,
  { label: string; variant: "success" | "warning" | "default" }
> = {
  beginner: { label: "Beginner", variant: "success" },
  intermediate: { label: "Intermediate", variant: "warning" },
  advanced: { label: "Advanced", variant: "default" },
};

export function LessonPlanView({
  title,
  description,
  difficulty,
  objectives,
  loading,
  onApprove,
  onUpdateObjectives,
  onBack,
}: LessonPlanProps) {
  const [editing, setEditing] = useState(false);
  const [editedObjectives, setEditedObjectives] = useState(objectives);
  const [editedDifficulty, setEditedDifficulty] = useState(difficulty);
  const [newObjective, setNewObjective] = useState("");

  if (loading) {
    return (
      <div className="mx-auto max-w-2xl space-y-4">
        <Skeleton className="h-8 w-48" />
        <Skeleton className="h-4 w-96" />
        <Skeleton className="h-4 w-72" />
        {[1, 2, 3, 4].map((i) => (
          <Skeleton key={i} className="h-16 w-full rounded-xl" />
        ))}
      </div>
    );
  }

  const handleSave = () => {
    onUpdateObjectives(editedObjectives, editedDifficulty);
    setEditing(false);
  };

  const handleCancel = () => {
    setEditedObjectives(objectives);
    setEditedDifficulty(difficulty);
    setEditing(false);
  };

  const handleAddObjective = () => {
    if (!newObjective.trim()) return;
    setEditedObjectives([
      ...editedObjectives,
      { text: newObjective.trim(), key_concepts: [], completed: false },
    ]);
    setNewObjective("");
  };

  const handleRemoveObjective = (index: number) => {
    setEditedObjectives(editedObjectives.filter((_, i) => i !== index));
  };

  const displayObjectives = editing ? editedObjectives : objectives;
  const displayDifficulty = editing ? editedDifficulty : difficulty;

  return (
    <div className="mx-auto max-w-2xl animate-slide-up space-y-6">
      <button
        onClick={onBack}
        className="flex items-center gap-1.5 text-sm text-muted-foreground hover:text-foreground transition-colors"
      >
        <ArrowLeft className="size-3.5" />
        Back to uploads
      </button>

      <div>
        <h2 className="text-2xl font-bold">Your Learning Plan</h2>
        {title && <p className="mt-1 text-muted-foreground">{title}</p>}
        {description && (
          <p className="mt-1 text-sm text-muted-foreground">{description}</p>
        )}
      </div>

      <div className="flex items-center gap-3">
        <div className="flex items-center gap-2 rounded-lg bg-muted px-3 py-1.5">
          <GraduationCap className="size-4 text-primary" />
          {editing ? (
            <select
              value={displayDifficulty}
              onChange={(e) => setEditedDifficulty(e.target.value)}
              className="bg-transparent text-sm font-medium outline-none"
            >
              <option value="beginner">Beginner</option>
              <option value="intermediate">Intermediate</option>
              <option value="advanced">Advanced</option>
            </select>
          ) : (
            <Badge
              variant={
                difficultyConfig[displayDifficulty]?.variant || "secondary"
              }
            >
              {difficultyConfig[displayDifficulty]?.label || displayDifficulty}
            </Badge>
          )}
        </div>
        <span className="text-sm text-muted-foreground">
          {objectives.length} learning objectives
        </span>
      </div>

      <div className="space-y-3">
        {displayObjectives.map((obj, i) => (
          <Card key={i} className="group transition-all hover:shadow-sm">
            <CardContent className="flex items-start gap-4 p-4">
              <div className="flex size-7 shrink-0 items-center justify-center rounded-full bg-gradient-to-br from-blue-500 to-indigo-600 text-xs font-bold text-white">
                {i + 1}
              </div>
              <div className="flex-1">
                {editing ? (
                  <input
                    type="text"
                    value={obj.text}
                    onChange={(e) => {
                      const copy = [...editedObjectives];
                      copy[i] = { ...copy[i], text: e.target.value };
                      setEditedObjectives(copy);
                    }}
                    className="w-full bg-transparent text-sm outline-none border-b border-border pb-0.5 focus:border-primary"
                  />
                ) : (
                  <p className="text-sm font-medium">{obj.text}</p>
                )}
                {obj.key_concepts.length > 0 && (
                  <div className="mt-2 flex flex-wrap gap-1.5">
                    {obj.key_concepts.map((concept) => (
                      <Badge key={concept} variant="secondary">
                        {concept}
                      </Badge>
                    ))}
                  </div>
                )}
              </div>
              {editing && (
                <Button
                  variant="ghost"
                  size="icon-xs"
                  onClick={() => handleRemoveObjective(i)}
                >
                  <Trash2 className="size-3.5 text-destructive" />
                </Button>
              )}
            </CardContent>
          </Card>
        ))}
      </div>

      {editing && (
        <div className="flex items-center gap-2">
          <input
            type="text"
            value={newObjective}
            onChange={(e) => setNewObjective(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && handleAddObjective()}
            placeholder="Add a new learning objective..."
            className="flex-1 rounded-md border border-border bg-background px-3 py-2 text-sm outline-none focus:border-primary"
          />
          <Button variant="outline" size="sm" onClick={handleAddObjective}>
            <Plus className="size-4" /> Add
          </Button>
        </div>
      )}

      <div className="flex items-center justify-between pt-4 border-t border-border">
        {editing ? (
          <div className="flex gap-2">
            <Button onClick={handleSave}>
              <Check className="size-4" /> Save Changes
            </Button>
            <Button variant="outline" onClick={handleCancel}>
              <X className="size-4" /> Cancel
            </Button>
          </div>
        ) : (
          <>
            <Button variant="outline" onClick={() => setEditing(true)}>
              <Edit3 className="size-4" /> Edit Plan
            </Button>
            <Button onClick={onApprove} size="lg" className="gap-2">
              <Play className="size-4" /> Start Learning
            </Button>
          </>
        )}
      </div>
    </div>
  );
}

import { useState, useEffect, useCallback } from "react";
import {
  CheckCircle2,
  XCircle,
  Lightbulb,
  BookOpen,
  ArrowRight,
  ChevronRight,
  RotateCcw,
  Loader2,
  Target,
} from "lucide-react";
import { Button } from "#components/ui/button";
import { Badge } from "#components/ui/badge";
import { Progress } from "#components/ui/progress";
import { Card, CardContent, CardHeader, CardTitle } from "#components/ui/card";
import { cn } from "#lib/utils";
import { api } from "#lib/api";
import type { MCQ } from "../types";

interface QuizWidgetProps {
  lessonPlanId: number;
  objectiveIndex: number;
  objectiveText: string;
  totalObjectives: number;
  questions: MCQ[];
  onComplete: (correct: number, total: number) => void;
  onNext: () => void;
}

type QuestionState = {
  status: "unanswered" | "correct" | "incorrect";
  selectedIndex: number | null;
  feedback: string;
  loadingFeedback: boolean;
};

export function QuizWidget({
  lessonPlanId,
  objectiveIndex,
  objectiveText,
  totalObjectives,
  questions,
  onComplete,
  onNext,
}: QuizWidgetProps) {
  const [qIndex, setQIndex] = useState(0);
  const [states, setStates] = useState<QuestionState[]>(() =>
    questions.map(() => ({
      status: "unanswered" as const,
      selectedIndex: null,
      feedback: "",
      loadingFeedback: false,
    }))
  );
  const [allCorrect, setAllCorrect] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  const currentQ = questions[qIndex];
  const currentState = states[qIndex];

  const correctCount = states.filter((s) => s.status === "correct").length;

  const handleSubmit = useCallback(() => {
    if (!currentState || currentState.selectedIndex === null) return;

    const isCorrect = currentState.selectedIndex === currentQ.correctIndex;

    const newStates = [...states];
    if (isCorrect) {
      newStates[qIndex] = {
        ...currentState,
        status: "correct",
        feedback: currentQ.explanation,
      };
    } else {
      newStates[qIndex] = {
        ...currentState,
        status: "incorrect",
        feedback: "That's not quite right. Try again or request a hint!",
        loadingFeedback: false,
      };
    }
    setStates(newStates);

    const allDone = newStates.every((s) => s.status === "correct");
    if (allDone && !allCorrect) {
      setAllCorrect(true);
    }
  }, [currentState, currentQ, states, qIndex, allCorrect]);

  const handleRetry = () => {
    const newStates = [...states];
    newStates[qIndex] = {
      status: "unanswered",
      selectedIndex: null,
      feedback: "",
      loadingFeedback: false,
    };
    setStates(newStates);
  };

  const handleHint = async () => {
    const newStates = [...states];
    newStates[qIndex] = { ...newStates[qIndex], loadingFeedback: true };
    setStates(newStates);

    try {
      const { hint } = await api.getHint({
        lessonPlanId,
        question: currentQ.question,
        choices: currentQ.choices,
        userAnswer:
          currentState.selectedIndex !== null
            ? currentQ.choices[currentState.selectedIndex]
            : "(no answer)",
      });
      const updatedStates = [...states];
      updatedStates[qIndex] = {
        ...updatedStates[qIndex],
        feedback: hint,
        loadingFeedback: false,
      };
      setStates(updatedStates);
    } catch {
      const updatedStates = [...states];
      updatedStates[qIndex] = {
        ...updatedStates[qIndex],
        feedback: "Think about the key concepts from the learning objective.",
        loadingFeedback: false,
      };
      setStates(updatedStates);
    }
  };

  const handleLearnMore = async () => {
    const newStates = [...states];
    newStates[qIndex] = { ...newStates[qIndex], loadingFeedback: true };
    setStates(newStates);

    try {
      const { explanation } = await api.learnMore({
        lessonPlanId,
        topic: currentQ.question,
        objective: objectiveText,
      });
      const updatedStates = [...states];
      updatedStates[qIndex] = {
        ...updatedStates[qIndex],
        feedback: explanation,
        loadingFeedback: false,
      };
      setStates(updatedStates);
    } catch {
      const updatedStates = [...states];
      updatedStates[qIndex] = {
        ...updatedStates[qIndex],
        feedback:
          "Review the learning objective and key concepts for this topic.",
        loadingFeedback: false,
      };
      setStates(updatedStates);
    }
  };

  const handleNext = () => {
    if (qIndex < questions.length - 1) {
      setQIndex(qIndex + 1);
    }
  };

  const handlePrev = () => {
    if (qIndex > 0) {
      setQIndex(qIndex - 1);
    }
  };

  const handleCompleteObjective = async () => {
    if (submitted) return;
    setSubmitted(true);
    onComplete(correctCount, questions.length);
  };

  return (
    <div className="mx-auto max-w-2xl animate-slide-up space-y-6">
      <div className="space-y-2">
        <div className="flex items-center justify-between">
          <Badge variant="default">
            Objective {objectiveIndex + 1} of {totalObjectives}
          </Badge>
          <span className="text-sm text-muted-foreground">
            Question {qIndex + 1} of {questions.length}
          </span>
        </div>
        <Progress
          value={((qIndex + (currentState?.status === "correct" ? 1 : 0)) / questions.length) * 100}
        />
      </div>

      <div>
        <div className="mb-2 flex items-center gap-2 text-sm text-muted-foreground">
          <Target className="size-4" />
          Learning Objective
        </div>
        <p className="text-sm font-medium">{objectiveText}</p>
      </div>

      <Card
        className={cn(
          "border-2 transition-colors",
          currentState?.status === "correct" && "border-success/50 bg-success/5",
          currentState?.status === "incorrect" && "border-destructive/50 bg-destructive/5"
        )}
      >
        <CardHeader>
          <CardTitle className="text-base font-semibold">
            {currentQ.question}
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-3">
          {currentQ.choices.map((choice, i) => {
            const isSelected = currentState?.selectedIndex === i;
            const isCorrectChoice = i === currentQ.correctIndex;
            const showResult =
              currentState?.status === "correct" ||
              currentState?.status === "incorrect";

            let bg = "bg-card hover:bg-muted/50";
            let border = "border-border";
            let ring = "";

            if (showResult && isSelected && currentState.status === "correct") {
              bg = "bg-success/10";
              border = "border-success";
              ring = "ring-1 ring-success/30";
            } else if (
              showResult &&
              isSelected &&
              currentState.status === "incorrect"
            ) {
              bg = "bg-destructive/10";
              border = "border-destructive";
              ring = "ring-1 ring-destructive/30";
            } else if (showResult && isCorrectChoice && currentState.status === "incorrect") {
              bg = "bg-success/5";
              border = "border-success/50";
            }

            return (
              <button
                key={i}
                disabled={currentState?.status === "correct" || currentState?.loadingFeedback}
                onClick={() => {
                  if (currentState?.status !== "correct") {
                    const newStates = [...states];
                    newStates[qIndex] = {
                      ...newStates[qIndex],
                      selectedIndex: i,
                    };
                    setStates(newStates);
                  }
                }}
                className={cn(
                  "flex w-full items-center gap-3 rounded-lg border p-3.5 text-left transition-all",
                  bg,
                  border,
                  ring,
                  !showResult && "cursor-pointer",
                  showResult && "cursor-default"
                )}
              >
                <div
                  className={cn(
                    "flex size-5 shrink-0 items-center justify-center rounded-full border-2 transition-colors",
                    isSelected
                      ? "border-primary bg-primary"
                      : "border-muted-foreground/30",
                    showResult &&
                      isSelected &&
                      currentState.status === "correct" &&
                      "border-success bg-success",
                    showResult &&
                      isSelected &&
                      currentState.status === "incorrect" &&
                      "border-destructive bg-destructive"
                  )}
                >
                  {showResult && isSelected && currentState.status === "correct" && (
                    <CheckCircle2 className="size-3.5 text-white" />
                  )}
                  {showResult && isSelected && currentState.status === "incorrect" && (
                    <XCircle className="size-3.5 text-white" />
                  )}
                  {isSelected && !showResult && (
                    <div className="size-2 rounded-full bg-white" />
                  )}
                </div>
                <span className="text-sm">{choice}</span>
              </button>
            );
          })}
        </CardContent>
      </Card>

      {currentState?.feedback && (
        <div
          className={cn(
            "rounded-xl border p-4 animate-slide-up",
            currentState.status === "correct"
              ? "border-success/50 bg-success/5"
              : "border-amber-500/30 bg-amber-500/5"
          )}
        >
          <div className="flex items-start gap-2">
            {currentState.status === "correct" ? (
              <CheckCircle2 className="size-5 text-success shrink-0 mt-0.5" />
            ) : (
              <Lightbulb className="size-5 text-amber-500 shrink-0 mt-0.5" />
            )}
            <div>
              <p className="text-sm font-medium mb-0.5">
                {currentState.status === "correct" ? "Correct!" : "Hint"}
              </p>
              <p className="text-sm text-muted-foreground">
                {currentState.loadingFeedback ? (
                  <span className="flex items-center gap-2">
                    <Loader2 className="size-3.5 animate-spin" />
                    Thinking...
                  </span>
                ) : (
                  currentState.feedback
                )}
              </p>
            </div>
          </div>
        </div>
      )}

      <div className="flex items-center justify-between gap-3 pt-2">
        <div className="flex gap-2">
          {currentState?.status === "incorrect" && (
            <>
              <Button variant="outline" size="sm" onClick={handleHint}>
                <Lightbulb className="size-4" /> Hint
              </Button>
              <Button variant="outline" size="sm" onClick={handleLearnMore}>
                <BookOpen className="size-4" /> Learn More
              </Button>
              <Button variant="outline" size="sm" onClick={handleRetry}>
                <RotateCcw className="size-4" /> Retry
              </Button>
            </>
          )}
        </div>

        <div className="flex gap-2 ml-auto">
          {currentState?.status === "unanswered" && (
            <Button
              onClick={handleSubmit}
              disabled={currentState?.selectedIndex === null}
            >
              Submit Answer
            </Button>
          )}
          {currentState?.status === "correct" && (
            <>
              {qIndex < questions.length - 1 ? (
                <Button onClick={handleNext}>
                  Next Question <ChevronRight className="size-4" />
                </Button>
              ) : (
                <Button
                  onClick={handleCompleteObjective}
                  disabled={submitted}
                  className="gap-2"
                >
                  {submitted ? (
                    <>
                      <Loader2 className="size-4 animate-spin" /> Saving...
                    </>
                  ) : (
                    <>
                      Complete Objective <ArrowRight className="size-4" />
                    </>
                  )}
                </Button>
              )}
            </>
          )}
        </div>
      </div>

      <div className="flex justify-center gap-1">
        {questions.map((_, i) => (
          <div
            key={i}
            className={cn(
              "size-2 rounded-full transition-all",
              states[i]?.status === "correct"
                ? "bg-success"
                : states[i]?.status === "incorrect"
                  ? "bg-destructive"
                  : i === qIndex
                    ? "bg-primary"
                    : "bg-muted-foreground/30"
            )}
          />
        ))}
      </div>
    </div>
  );
}

