import { useState, useEffect, useCallback } from "react";
import {
  Loader2,
  Brain,
  BookOpen,
  GraduationCap,
} from "lucide-react";
import { Button } from "#components/ui/button";
import { Spinner } from "#components/ui/spinner";
import { FileUpload } from "./components/FileUpload";
import { PdfHistory } from "./components/PdfHistory";
import { LessonPlanView } from "./components/LessonPlanView";
import { QuizWidget } from "./components/QuizWidget";
import { SummaryView } from "./components/SummaryView";
import { api } from "#lib/api";
import type {
  AppScreen,
  PdfDocument,
  LessonPlan,
  MCQ,
  LessonSummary,
} from "./types";

export default function App() {
  const [screen, setScreen] = useState<AppScreen>("home");

  const [pdfs, setPdfs] = useState<PdfDocument[]>([]);
  const [pdfsLoading, setPdfsLoading] = useState(true);
  const [uploading, setUploading] = useState(false);

  const [selectedPdf, setSelectedPdf] = useState<PdfDocument | null>(null);
  const [lessonPlan, setLessonPlan] = useState<LessonPlan | null>(null);
  const [planLoading, setPlanLoading] = useState(false);

  const [currentObjectiveIndex, setCurrentObjectiveIndex] = useState(0);
  const [quizQuestions, setQuizQuestions] = useState<MCQ[] | null>(null);
  const [quizLoading, setQuizLoading] = useState(false);

  const [summary, setSummary] = useState<LessonSummary | null>(null);
  const [summaryLoading, setSummaryLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const loadPdfs = useCallback(async () => {
    setPdfsLoading(true);
    try {
      const data = await api.getPdfs();
      setPdfs(data);
    } catch {
      // Silent
    } finally {
      setPdfsLoading(false);
    }
  }, []);

  useEffect(() => {
    loadPdfs();
  }, [loadPdfs]);

  const handleUpload = async (file: File) => {
    setUploading(true);
    setError(null);
    try {
      const result = await api.uploadPdf(file);
      await loadPdfs();
      const pdf: PdfDocument = {
        id: result.id,
        filename: result.filename,
        created_at: new Date().toISOString(),
        status: "uploaded",
      };
      setSelectedPdf(pdf);
    } catch (e: any) {
      setError(e.message || "Upload failed");
    } finally {
      setUploading(false);
    }
  };

  const handleSelectPdf = async (pdf: PdfDocument) => {
    setSelectedPdf(pdf);
    setError(null);

    if (pdf.status === "completed") {
      setPlanLoading(true);
      try {
        const plan = await api.getLessonPlan(pdf.id);
        setLessonPlan(plan);
        setScreen("lesson-plan");
      } catch {
        setError("Could not load lesson plan");
      } finally {
        setPlanLoading(false);
      }
      return;
    }

    if (pdf.status === "approved") {
      setPlanLoading(true);
      try {
        const plan = await api.getLessonPlan(pdf.id);
        setLessonPlan(plan);
        const progress = await api.getProgress(plan.id);
        const nextIncomplete = (progress.objectives || plan.objectives).findIndex(
          (o: any) => !o.completed
        );
        if (nextIncomplete === -1) {
          await loadSummary(plan.id);
          return;
        }
        setCurrentObjectiveIndex(nextIncomplete);
        setScreen("quiz");
        await loadQuiz(plan.id, nextIncomplete);
      } catch {
        setError("Could not load lesson");
      } finally {
        setPlanLoading(false);
      }
      return;
    }

    setPlanLoading(true);
    try {
      const plan = await api.getLessonPlan(pdf.id);
      if (plan) {
        setLessonPlan(plan);
        setScreen("lesson-plan");
      } else {
        const newPlan = await api.generateLessonPlan(pdf.id);
        setLessonPlan(newPlan);
        setScreen("lesson-plan");
      }
    } catch {
      const newPlan = await api.generateLessonPlan(pdf.id);
      setLessonPlan(newPlan);
      setScreen("lesson-plan");
    } finally {
      setPlanLoading(false);
    }
  };

  const handleDeletePdf = async (id: number) => {
    try {
      await api.deletePdf(id);
      await loadPdfs();
    } catch {}
  };

  const handleApprovePlan = async () => {
    if (!lessonPlan) return;
    try {
      await api.approveLessonPlan(lessonPlan.id);
      setLessonPlan({ ...lessonPlan, status: "approved" });
      setCurrentObjectiveIndex(0);
      setScreen("quiz");
      await loadQuiz(lessonPlan.id, 0);
    } catch (e: any) {
      setError(e.message || "Failed to approve plan");
    }
  };

  const handleUpdateObjectives = async (
    objectives: LessonPlan["objectives"],
    difficulty: string
  ) => {
    if (!lessonPlan) return;
    try {
      await api.updateObjectives(lessonPlan.id, objectives, difficulty);
      setLessonPlan({
        ...lessonPlan,
        objectives,
        difficulty: difficulty as LessonPlan["difficulty"],
        status: "approved",
      });
    } catch (e: any) {
      setError(e.message || "Failed to update plan");
    }
  };

  const loadQuiz = async (planId: number, objIndex: number) => {
    setQuizLoading(true);
    setQuizQuestions(null);
    try {
      const data = await api.generateQuiz(planId, objIndex);
      setQuizQuestions(data.questions);
    } catch (e: any) {
      setError(e.message || "Failed to generate quiz");
    } finally {
      setQuizLoading(false);
    }
  };

  const handleQuizComplete = async (correct: number, total: number) => {
    if (!lessonPlan) return;
    try {
      await api.submitResult({
        lessonPlanId: lessonPlan.id,
        objectiveIndex: currentObjectiveIndex,
        objectiveText: lessonPlan.objectives[currentObjectiveIndex].text,
        totalQuestions: total,
        correctAnswers: correct,
      });
    } catch {}

    const nextIndex = currentObjectiveIndex + 1;
    if (nextIndex < lessonPlan.objectives.length) {
      setCurrentObjectiveIndex(nextIndex);
      await loadQuiz(lessonPlan.id, nextIndex);
    } else {
      await loadSummary(lessonPlan.id);
    }
  };

  const loadSummary = async (planId: number) => {
    setSummaryLoading(true);
    setScreen("summary");
    try {
      const data = await api.getSummary(planId);
      setSummary(data);
    } catch (e: any) {
      setError(e.message || "Failed to generate summary");
    } finally {
      setSummaryLoading(false);
    }
  };

  const handleRetest = () => {
    if (!lessonPlan) return;
    const freshPlan = {
      ...lessonPlan,
      objectives: lessonPlan.objectives.map((o) => ({
        ...o,
        completed: false,
      })),
      status: "approved" as const,
    };
    setLessonPlan(freshPlan);
    setCurrentObjectiveIndex(0);
    setQuizQuestions(null);
    setSummary(null);
    setScreen("quiz");
    loadQuiz(freshPlan.id, 0);
  };

  const handleNewUpload = () => {
    setScreen("home");
    setSelectedPdf(null);
    setLessonPlan(null);
    setQuizQuestions(null);
    setSummary(null);
    setCurrentObjectiveIndex(0);
    setError(null);
  };

  const handleBackToPlan = () => {
    setScreen("lesson-plan");
  };

  return (
    <div className="min-h-screen bg-gradient-to-b from-background to-muted/30">
      <header className="sticky top-0 z-50 border-b border-border/50 bg-background/80 backdrop-blur-xl">
        <div className="mx-auto flex max-w-5xl items-center justify-between px-6 py-3">
          <button
            onClick={handleNewUpload}
            className="flex items-center gap-2.5"
          >
            <div className="flex size-9 items-center justify-center rounded-xl bg-gradient-to-br from-blue-500 to-indigo-600 shadow-md shadow-indigo-500/25">
              <Brain className="size-5 text-white" />
            </div>
            <div>
              <h1 className="text-lg font-bold tracking-tight">Learnify</h1>
              <p className="text-[10px] text-muted-foreground -mt-0.5">
                AI Learning Agent
              </p>
            </div>
          </button>

          {screen !== "home" && (
            <Button variant="ghost" size="sm" onClick={handleNewUpload}>
              New Upload
            </Button>
          )}
        </div>
      </header>

      <main className="mx-auto max-w-5xl px-6 py-8">
        {error && (
          <div className="mb-6 animate-slide-up rounded-xl border border-destructive/50 bg-destructive/5 p-4">
            <p className="text-sm text-destructive">{error}</p>
            <button
              onClick={() => setError(null)}
              className="mt-1 text-xs text-destructive/70 hover:text-destructive"
            >
              Dismiss
            </button>
          </div>
        )}

        {screen === "home" && (
          <div className="animate-fade-in space-y-8">
            <div className="text-center space-y-3">
              <h2 className="text-3xl font-bold tracking-tight">
                Learn from any PDF
              </h2>
              <p className="text-muted-foreground max-w-md mx-auto">
                Upload a PDF document and our AI agent creates an interactive
                lesson plan with quizzes, feedback, and study tips.
              </p>
            </div>

            <FileUpload onUpload={handleUpload} loading={uploading} />

            {planLoading && (
              <div className="flex flex-col items-center gap-3 py-8">
                <Spinner className="size-8 text-primary" />
                <p className="text-sm text-muted-foreground">
                  Generating your learning plan...
                </p>
              </div>
            )}

            <PdfHistory
              pdfs={pdfs}
              loading={pdfsLoading}
              onSelect={handleSelectPdf}
              onDelete={handleDeletePdf}
            />
          </div>
        )}

        {screen === "lesson-plan" && lessonPlan && (
          <LessonPlanView
            title={lessonPlan.title}
            description={lessonPlan.description}
            difficulty={lessonPlan.difficulty}
            objectives={lessonPlan.objectives}
            loading={planLoading}
            onApprove={handleApprovePlan}
            onUpdateObjectives={handleUpdateObjectives}
            onBack={handleNewUpload}
          />
        )}

        {screen === "quiz" && lessonPlan && (
          <div className="animate-slide-up space-y-6">
            {quizLoading ? (
              <div className="flex flex-col items-center gap-4 py-16">
                <Spinner className="size-10 text-primary" />
                <p className="text-sm text-muted-foreground">
                  Generating quiz questions...
                </p>
              </div>
            ) : quizQuestions ? (
              <QuizWidget
                key={`${lessonPlan.id}-${currentObjectiveIndex}`}
                lessonPlanId={lessonPlan.id}
                objectiveIndex={currentObjectiveIndex}
                objectiveText={
                  lessonPlan.objectives[currentObjectiveIndex].text
                }
                totalObjectives={lessonPlan.objectives.length}
                questions={quizQuestions}
                onComplete={handleQuizComplete}
                onNext={() => {}}
              />
            ) : (
              <div className="flex flex-col items-center gap-4 py-16">
                <p className="text-muted-foreground">
                  Could not load questions
                </p>
                <Button onClick={() => loadQuiz(lessonPlan.id, currentObjectiveIndex)}>
                  Retry
                </Button>
              </div>
            )}
          </div>
        )}

        {screen === "summary" && (
          <SummaryView
            summary={summary}
            loading={summaryLoading}
            onRetest={handleRetest}
            onNewUpload={handleNewUpload}
          />
        )}
      </main>

      <footer className="border-t border-border/50 py-4 text-center">
        <p className="text-xs text-muted-foreground">
          Learnify - AI Learning Agent
        </p>
      </footer>
    </div>
  );
}

